INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','hero','header_title','h1','Coliback Premium',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','hero','header_breadcrumb','label','home / projets',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_p1','paragraph','Au cours de mon alternance réalisée dans le cadre du Master Ingénierie Logicielle de l''ISCOD, j''ai participé à la conception et au développement de ColiBack Premium, une plateforme numérique destinée à automatiser les procédures de retour et d''échange de produits pour les boutiques e-commerce utilisant Shopify.\n\nJ''ai intégré ColiBack en octobre 2024 au sein de l''équipe technique pilotée par David Dias, Directeur des Systèmes d''Information. Cette alternance m''a permis de découvrir un environnement où les enjeux logistiques et numériques sont étroitement liés. Historiquement spécialisée dans la gestion des retours colis, ColiBack a progressivement développé un ensemble de solutions logicielles permettant aux e-commerçants d''externaliser une partie de leurs processus logistiques.\n\nL''entreprise appartient au réseau national E-Logik et s''appuie notamment sur la solution E-Kan pour assurer le suivi des commandes, des stocks et des mouvements logistiques.\n\nDans ce contexte, l''objectif du projet était de concevoir une solution capable de s''intégrer naturellement à cet écosystème tout en répondant à une problématique croissante observée chez les clients : la gestion des retours et des échanges de produits issus des boutiques Shopify.\n\nAvant le développement de ColiBack Premium, les solutions existantes permettaient principalement de déclarer un retour produit. Les processus d''échange restaient largement manuels et nécessitaient l''intervention des équipes support ou logistiques. Cette situation générait des délais de traitement importants, une charge opérationnelle élevée ainsi qu''une expérience utilisateur parfois insatisfaisante pour les consommateurs finaux.\n\nLe projet visait donc à concevoir un véritable moteur métier capable d''automatiser l''ensemble du cycle de retour : identification des produits retournables, sélection de variantes alternatives disponibles, création des retours Shopify, génération des étiquettes transporteurs et création automatique des commandes d''échange.\n\nLes contraintes imposées par Shopify nécessitaient une maîtrise avancée des API GraphQL, des mécanismes OAuth, de la sécurisation des échanges de données ainsi que des problématiques d''architecture logicielle distribuée.\n\nCette réalisation m''a permis de développer plusieurs compétences fondamentales du Master Ingénierie Logicielle :',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_1','list_item','conception d''architectures logicielles orientées services ;',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_2','list_item','développement d''API sécurisées ;',3);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_3','list_item','intégration de systèmes tiers ;',4);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_4','list_item','gestion de projet Agile ;',5);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_5','list_item','pratiques DevOps et déploiement cloud ;',6);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_6','list_item','sécurité applicative et conformité RGPD ;',7);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','intro','intro_comp_7','list_item','travail collaboratif avec des équipes métiers et techniques.',8);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_title','h2','1. Objectifs du projet',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_1_title','h3','1.1  Concevoir une solution informatique évolutive',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_1_text','paragraph','Le premier objectif consistait à développer une plateforme capable d''être déployée rapidement auprès de nouveaux clients tout en garantissant une forte capacité d''évolution.\nLa croissance continue de l''écosystème Shopify imposait de concevoir une architecture suffisamment flexible pour absorber les évolutions de l''API et les nouvelles attentes des e-commerçants sans nécessiter de refonte majeure.\n\nJ''ai donc participé à la conception d''une architecture modulaire respectant les principes SOLID afin de garantir la maintenabilité du logiciel sur le long terme.',3);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_2_title','h3','1.2  Enrichir le système d''information de ColiBack',4);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_2_text','paragraph','Le second objectif consistait à faire évoluer l''offre numérique de ColiBack.\n\nL''entreprise disposait déjà d''outils permettant de suivre les flux logistiques, les commandes et les stocks. L''ajout de ColiBack Premium devait permettre de compléter cette chaîne numérique en automatisant la gestion des retours et des échanges directement depuis les boutiques Shopify.\n\nCette évolution représentait un avantage concurrentiel important puisqu''elle permettait à ColiBack de proposer un service complémentaire à forte valeur ajoutée tout en réduisant la charge opérationnelle des équipes logistiques.',5);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_3_title','h3','1.2  Mettre en pratique les compétences du Master',6);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','objectifs','ch1_3_text','paragraph','Ce projet représentait également l''occasion de mettre en œuvre les méthodes et technologies étudiées durant ma formation.\n\nJ''ai ainsi pu appliquer concrètement des notions d''architecture logicielle, de gestion de projet Agile, de développement d''API REST, d''intégration GraphQL, de conteneurisation Docker ainsi que de sécurisation des infrastructures cloud.',7);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','contexte','ch2_title','h2','2. Contexte humain et technique',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','contexte','ch2_1_title','h3','2.1 Les acteurs du projet',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','contexte','ch2_1_text','paragraph','Le développement de ColiBack Premium a mobilisé plusieurs profils complémentaires.\nDavid Dias intervenait en qualité de commanditaire et de responsable technique. Son rôle consistait à définir les besoins métiers et les orientations stratégiques du projet.\n\nLes développeurs E-Logik conseillaient sur le plan technique et normatif afin de garantir la cohérence des flux logistiques sur la plateforme e-kan et la bonne compréhension des concepts Shopify.\nLes e-commerçants partenaires ont également joué un rôle important dans la validation fonctionnelle du produit grâce à leurs retours d''expérience.\n\nEnfin, plusieurs experts techniques sont intervenus ponctuellement pour apporter leur expertise sur les sujets liés à l''architecture logicielle, à la sécurité et au déploiement cloud.',3);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','contexte','ch2_2_title','h3','2.2 Environnement technique',4);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','contexte','ch2_2_text','paragraph','Le projet repose sur une architecture moderne construite autour de NodeJS et ExpressJS.\nLe serveur applicatif agit comme une couche intermédiaire entre les boutiques Shopify et les différents services ColiBack.\n\nLes données techniques sont stockées dans une base MariaDB hébergée dans un conteneur Docker.\nL''infrastructure est déployée sur un serveur Ubuntu hébergé chez OVH et protégée par Nginx qui assure le rôle de reverse proxy ainsi que la terminaison TLS grâce aux certificats Let''s Encrypt.\n\nLe choix de NodeJS s''est imposé pour sa capacité à gérer efficacement un grand nombre de requêtes asynchrones vers l''API Shopify.\n\nL''utilisation de Docker permet quant à elle de standardiser les environnements de développement et de production tout en facilitant les opérations de maintenance.\n\nEnfin, GraphQL a été retenu comme technologie principale d''interfaçage avec Shopify puisque cette dernière remplace progressivement ses anciennes API REST.\n\nL''ensemble de cette architecture répond à un objectif de scalabilité, de sécurité et de maintenabilité permettant d''accompagner la croissance future du service.',5);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','enjeux','ch3_title','h2','3. Enjeux et risques du projet',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','enjeux','ch3_1_title','h3','3.1 Enjeux du projet',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','enjeux','ch3_1_text','paragraph','Le projet Coliback Premium représentait un enjeu stratégique pour Coliback puisqu''il visait à enrichir l''offre de services numériques proposée aux e-commerçants partenaires. L''objectif était de proposer une solution moderne permettant aux clients finaux de gérer eux-mêmes leurs demandes de retour ou d''échange directement depuis une interface dédiée.\n\nLe premier enjeu concernait la satisfaction des clients e-commerçants. Jusqu''alors, certaines opérations liées aux retours et aux échanges nécessitaient des interventions manuelles ou l''utilisation de solutions tierces souvent coûteuses. Coliback Premium devait permettre d''automatiser ces traitements tout en offrant une expérience utilisateur fluide aux consommateurs.\n\nUn second enjeu était l''intégration durable avec l''écosystème Shopify. Le projet dépendant fortement des API Shopify, il était indispensable de concevoir une architecture suffisamment souple pour s''adapter aux évolutions régulières de la plateforme tout en respectant les bonnes pratiques imposées par sa documentation technique.\n\nL''évolutivité constituait également un enjeu majeur. La solution devait pouvoir accueillir progressivement de nouveaux clients sans nécessiter de refonte de l''architecture. Cette exigence a conduit à concevoir une architecture multi-boutiques reposant sur l''identification des différentes boutiques via un système de shopId et de tokens d''accès indépendants.\n\nLa sécurité représentait également un enjeu central. Le service manipulant des commandes, des informations de livraison et des accès aux boutiques Shopify, il était indispensable de protéger les échanges de données, de limiter les accès aux ressources sensibles et de respecter les principes du RGPD.\n\nEnfin, le projet devait être réalisé dans des délais compatibles avec les attentes de la Direction Technique et des premiers clients pilotes intéressés par la solution.',3);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','enjeux','ch3_2_title','h3','3.2 Risques identifiés',4);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','enjeux','ch3_2_text','paragraph','Plusieurs risques ont été identifiés dès le lancement du projet.\nLe premier concernait la complexité technique liée à l''intégration avec Shopify. La plateforme impose ses propres mécanismes d''authentification, son modèle de données GraphQL ainsi que des règles métier spécifiques concernant les retours, les échanges et la gestion des commandes. Une mauvaise compréhension de ces mécanismes aurait pu compromettre le bon fonctionnement du projet.\n\nUn risque d''architecture existait également. Des choix techniques inadaptés au début du projet auraient pu conduire à une solution difficile à maintenir ou incapable d''évoluer avec les besoins futurs de Coliback.\nLa sécurité représentait un autre risque important. Une mauvaise gestion des tokens Shopify ou des accès aux API aurait pu exposer les données des boutiques partenaires ou compromettre l''intégrité du système d''information de Coliback.\n\nLe risque de performance devait également être pris en compte. Le service étant destiné à être utilisé simultanément par plusieurs boutiques et plusieurs utilisateurs, il était nécessaire de concevoir une architecture capable de supporter une montée en charge progressive.\n\nEnfin, un risque fonctionnel concernait la compréhension des besoins réels des utilisateurs. Une mauvaise analyse des attentes des e-commerçants ou des clients finaux aurait pu conduire au développement de fonctionnalités peu adaptées aux usages du terrain.',5);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_title','h2','4. Étapes du projet',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_1_title','h3','4.1 Étude du besoin et définition du projet',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_1_text','paragraph','Le projet a débuté par plusieurs échanges avec le Directeur Technique afin de comprendre les objectifs métier et les attentes de Coliback.\n\nCette phase a permis d''identifier les problématiques rencontrées par les e-commerçants dans la gestion des retours et des échanges, mais également les contraintes imposées par Shopify et par l''écosystème informatique déjà en place chez Coliback.\n\nL''analyse du besoin a conduit à définir les principales fonctionnalités attendues :',3);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_1_item1','list_item','consultation des produits retournables ;',4);
