INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_2_text','paragraph','Une phase de veille a ensuite été menée afin d''étudier les technologies imposées par Shopify et d''identifier les solutions techniques adaptées au projet.\n\nCette étude a porté notamment sur :',11);
