INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_3_title','h3','4.3 Conception et développement du MVP',24);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_3_text','paragraph','La première version du produit a été développée sous la forme d''un MVP (Minimum Viable Product).\nL''objectif était de valider rapidement les principaux workflows métier avant d''enrichir progressivement la solution.\n\nLes premières fonctionnalités développées ont été :',25);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_3_item1','list_item','récupération des commandes Shopify ;',26);
