INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_4_title','h3','4.4 Mise en place d''une organisation Agile',31);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_4_text','paragraph','Afin d''assurer un suivi régulier du projet, les développements ont été organisés selon une approche Agile.\nLes fonctionnalités ont été découpées en tâches unitaires puis intégrées dans un backlog de développement.\n\nCette organisation a permis :',32);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_4_item1','list_item','de suivre l''avancement du projet ;',33);
