INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_5_title','h3','4.5 Conception de l''architecture logicielle',37);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_5_text','paragraph','Une attention particulière a été portée à la conception de l''architecture.\nLe projet a été construit autour d''une architecture orientée services (SOA) composée de plusieurs couches distinctes :',38);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_5_item1','list_item','Routes ;',39);
