INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_5_text2','paragraph','Cette organisation permet de séparer les responsabilités et facilite la maintenance du logiciel.\nL''architecture a également été conçue pour respecter les principes SOLID et favoriser les évolutions futures de la plateforme.',43);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_6_title','h3','4.6 Développement des fonctionnalités et tests',44);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_6_text','paragraph','Les principales fonctionnalités métier ont ensuite été développées.\n\nLes trois routes principales du service ont été conçues afin de répondre aux besoins du workflow de retour :',45);
