INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_6_text3','paragraph','Cette phase a permis d''améliorer la robustesse du service avant son déploiement.',55);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_title','h3','4.7 Déploiement de la solution dans le cloud',56);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_text','paragraph','Une fois les développements validés, l''application a été déployée sur une infrastructure cloud hébergée chez OVH.\n\nCette étape a nécessité l''acquisition de nouvelles compétences en administration système et en DevOps.\nL''infrastructure mise en place repose sur :',57);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_item1','list_item','Ubuntu ;',58);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_item2','list_item','Docker ;',59);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_item3','list_item','MariaDB ;',60);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_item4','list_item','Nginx ;',61);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_item5','list_item','Let''s Encrypt.',62);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_7_text2','paragraph','Cette architecture garantit une bonne isolation des services tout en facilitant les futures évolutions de la plateforme.',63);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_8_title','h3','4.8 Présentation de la solution aux utilisateurs',64);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_8_text','paragraph','Après sa mise en production, Coliback Premium a été présenté à différents partenaires et clients potentiels.\n\nLa solution a notamment été présentée lors d''événements liés à l''écosystème Shopify ainsi qu''aux partenaires de Coliback et E-Kan.\n\nCes démonstrations ont permis de recueillir des retours utilisateurs utiles pour les évolutions futures du produit.',65);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_title','h3','4.9 Maintenance corrective et évolutive',66);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_text','paragraph','Depuis sa mise en production, le projet fait l''objet d''une maintenance continue.\n\nLes actions réalisées concernent notamment :',67);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_item1','list_item','la correction d''anomalies ;',68);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_item2','list_item','l''amélioration des performances ;',69);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_item3','list_item','l''ajout de nouvelles fonctionnalités ;',70);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_item4','list_item','l''adaptation aux évolutions de l''API Shopify.',71);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','realisation','ch4_9_text2','paragraph','Cette phase constitue aujourd''hui une partie importante du cycle de vie du projet.',72);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','methodologie','ch5_title','h2','5. Méthodologie adoptée',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','methodologie','ch5_text','paragraph','Pour mener à bien le projet Coliback Premium, une méthodologie Agile a été privilégiée.\nCette approche était particulièrement adaptée au contexte du projet, les besoins pouvant évoluer au fur et à mesure des échanges avec les utilisateurs et de la découverte des contraintes techniques de Shopify.\n\nLe projet a été découpé en plusieurs phases successives permettant de livrer progressivement des fonctionnalités utilisables. Chaque étape faisait l''objet d''une validation avant le lancement de la suivante.\n\nLes fonctionnalités ont été organisées sous forme de backlog afin de faciliter leur priorisation et leur suivi. Cette organisation a permis d''adapter rapidement le développement aux retours des utilisateurs et aux nouvelles contraintes identifiées durant le projet.\n\nDes échanges réguliers avec le Directeur Technique et les différents acteurs du projet ont également permis d''assurer une bonne cohérence entre les besoins métier et les choix techniques réalisés.\n\nCette méthode de travail a favorisé l''amélioration continue de la solution tout au long de son développement.',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_title','h2','6. Fin du projet et perspectives d''avenir',1);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_intro','paragraph','Le développement de Coliback Premium a permis à Coliback de disposer d''une nouvelle solution capable d''automatiser la gestion des retours et des échanges pour les boutiques Shopify.\n\nAu-delà de la réalisation technique, ce projet a constitué pour moi une expérience particulièrement enrichissante puisqu''il s''agit du premier projet professionnel complet que j''ai eu l''occasion de concevoir, développer, déployer et maintenir dans un contexte réel d''entreprise.\n\nCette expérience m''a permis de mieux comprendre les différentes étapes du cycle de vie d''un projet logiciel, depuis l''analyse du besoin jusqu''à la mise en production et au suivi des utilisateurs.\n\nÀ l''avenir, plusieurs évolutions sont envisagées pour poursuivre le développement de la solution :',2);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_item1','list_item','ajout de nouvelles fonctionnalités de personnalisation ;',3);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_item2','list_item','amélioration du suivi des retours et des échanges ;',4);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_item3','list_item','intégration de nouveaux transporteurs ;',5);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_item4','list_item','extension du service à d''autres plateformes e-commerce ;',6);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_item5','list_item','amélioration des mécanismes de supervision et de monitoring ;',7);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_item6','list_item','automatisation plus poussée des déploiements via des outils DevOps.',8);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','conclusion','ch6_text2','paragraph','Ces perspectives permettront à Coliback Premium de continuer à évoluer afin de répondre aux besoins croissants des e-commerçants tout en conservant une architecture robuste, maintenable et évolutive.',9);
INSERT INTO content_blocks (page_slug,category,block_key,type,value,order_index) VALUES ('coliback-premium','projets','projects_title','h2','projets',1);
